mapper.select:
SELECT a.online, -- 本年度上线数量 a.views, -- 本年度观看量 a.intr, -- 互动率 b.amount, -- 本年度红人总花费 a.spend, -- 本年度投流总花费 ROUND((b.amount/a.views)*1000,4) AS 'cpm', -- 本年度CPM c.gmv, -- GMV ROUND(c.gmv/(b.amount+a.spend),4) AS 'roas' -- ROAS FROM ( SELECT COUNT(a.online_url) AS 'online', -- 本年度上线数量：内容发布时间的维度统计内容数量 SUM(a.views) AS 'views', -- 本年度观看量：内容发布时间的维度统计内容的观看量之和 ROUND((SUM(a.likes)+SUM(a.comments)+SUM(a.shares)+SUM(a.favors))/SUM(a.views),4) AS 'intr', -- 互动率=(点赞+评论+分享+收藏)/观看量，每个变量是统计内容里对应的数据之和 SUM(a.spend) AS 'spend' -- 本年度投流总花费：内容发布时间的维度统计内容的广告消耗金额之和 FROM a_hot_coop_data a LEFT JOIN `a_hot_coop` b ON b.id = a.coop_id WHERE a.del_flag = 0 AND b.del_flag = 0 AND YEAR(a.rele_time) = #{date}
AND b.`country` = #{country}
) a LEFT JOIN ( SELECT SUM(amount) AS 'amount' -- 本年度红人总花费：按照合作单里的付款时间所属年度下对应的付款金额统计 FROM `a_hot_coop_data` a LEFT JOIN `a_hot_coop` b ON b.id = a.coop_id WHERE a.del_flag = 0 AND b.del_flag = 0 AND YEAR(a.pay_time) = #{date}
AND b.`country` = #{country}
) b ON 1=1 LEFT JOIN ( SELECT SUM(gmv) AS 'gmv' FROM `a_hot_coop_product` a LEFT JOIN `a_hot_coop` b ON b.id = a.coop_id WHERE a.del_flag = 0 AND b.del_flag = 0 AND YEAR(a.sales_period) = #{date}
AND b.`country` = #{country}
) c ON 1=1
